+    this.peer.addEventListener("connectionstatechange", () => {
+      if (this.closed) {
+        return;
+      }
+      if (this.peer?.connectionState === "failed" || this.peer?.connectionState === "closed") {
+        this.ctx.callbacks.onStatus?.("error", "Realtime connection closed");
+      }
+    });
