+    }
+    this.toolBuffers.set(key, {
+      name: event.name ?? "",
+      callId: event.call_id ?? "",
+      args: event.delta ?? "",
+    });
+  }
+
+  private async handleToolCall(event: RealtimeServerEvent): Promise<void> {
+    const key = event.item_id ?? "unknown";
+    const buffered = this.toolBuffers.get(key);
